GUICustomShopSubTab = class("GUICustomShopSubTab", IGUIWindow)

function GUICustomShopSubTab:onLoad()
    self.cbTab = self:getChildWindowByName("BedWarCustomShopSubTab", GUIType.CheckBox)
    self.tvName = self:getChildWindowByName("BedWarCustomShopSubTab-Name", GUIType.StaticText)

    self.cbTab:registerEvent(GUIEvent.Click, function()
        SoundUtil.playSound(SoundConfig.selectTabStore)
    end)
end

function GUICustomShopSubTab:onDataChanged(data)
    self.type = data.Type
    self.tabId = data.TabId
    self.tvName:SetText(Lang:getString(data.Lang))
end

function GUICustomShopSubTab:setChecked(check)
    self.cbTab:SetChecked(check)
    self.cbTab:SetTouchable(not check)
end